"use client";

/**
 * Opener for the `whatsappMedia` overlay.
 *
 * - `useOpenWhatsAppMediaWindow()` — imperative hook. Call to open with typed options;
 *   returns a handle with a `close()` method.
 * - `<WhatsAppMediaWindowController />` — declarative wrapper. Mount to open,
 *   unmount to close. Equivalent ergonomics to rendering a normal component.
 *
 * Generated by scripts/generate-overlay-controller.ts (`openers` mode).
 * Hand-edit freely after the initial seed; the script will not re-emit a
 * file that already exists unless invoked with --force.
 */

import { useCallback, useEffect } from "react";
import { useAppDispatch } from "@/lib/redux/hooks";
import { closeOverlay, openOverlay } from "@/lib/redux/slices/overlaySlice";

const OVERLAY_ID = "whatsappMedia" as const;

export interface OpenWhatsAppMediaWindowOptions {
  /** TODO: tighten to `MediaTabId` once that type is imported. */
  initialTabId?: unknown;
}

export interface WhatsAppMediaWindowHandle {
  close: () => void;
}

export function useOpenWhatsAppMediaWindow() {
  const dispatch = useAppDispatch();
  return useCallback(
    (opts: OpenWhatsAppMediaWindowOptions = {}): WhatsAppMediaWindowHandle => {
      dispatch(
        openOverlay({
          overlayId: OVERLAY_ID,
          data: {
            initialTabId: opts.initialTabId,
          },
        }),
      );
      return {
        close: () => dispatch(closeOverlay({ overlayId: OVERLAY_ID })),
      };
    },
    [dispatch],
  );
}

/**
 * Declarative form. Renders nothing visible; opens the overlay on mount,
 * closes it on unmount. Use this when a caller wants to express overlay
 * state declaratively (the way they'd render a normal component).
 */
export function WhatsAppMediaWindowController(props: OpenWhatsAppMediaWindowOptions): null {
  const open = useOpenWhatsAppMediaWindow();
  useEffect(() => {
    const handle = open(props);
    return () => handle.close();
  }, [open, props.initialTabId]);
  return null;
}
